  1	import {
  2	  Button,
  3	  DataList,
  4	  DataListCell,
  5	  DataListCheck,
  6	  DataListControl,
  7	  DataListDragButton,
  8	  DataListItem,
  9	  DataListItemCells,
 10	  DataListItemRow,
 11	  DragDrop,
 12	  Draggable,
 13	  Droppable,
 14	  Flex,
 15	  FlexItem,
 16	  Text,
 17	  TextContent,
 18	  TextVariants,
 19	  Tooltip
 20	} from '@patternfly/react-core';
 21	import * as _ from 'lodash';
 22	import * as React from 'react';
 23	import { useTranslation } from 'react-i18next';
 24	import { Config } from '../../model/config';
 25	import { Column, ColumnSizeMap, getDefaultColumns, getFullColumnName } from '../../utils/columns';
 26	import './columns-modal.css';
 27	import Modal from './modal';
 28	
 29	const COLUMNS_DRAG_ZONE = 'netobs-columns-modal';
 30	
 31	export const columnFilterKeys = ['source', 'destination', 'time', 'host', 'namespace', 'owner', 'ip', 'dns'];
 32	
 33	export interface ColumnsModalProps {
 34	  isModalOpen: boolean;
 35	  setModalOpen: (v: boolean) => void;
 36	  columns: Column[];
 37	  setColumns: (v: Column[]) => void;
 38	  setColumnSizes: (v: ColumnSizeMap) => void;
 39	  config: Config;
 40	  id?: string;
 41	}
 42	
 43	export const ColumnsModal: React.FC<ColumnsModalProps> = ({
 44	  id,
 45	  config,
 46	  isModalOpen,
 47	  setModalOpen,
 48	  columns,
 49	  setColumns,
 50	  setColumnSizes
 51	}) => {
 52	  const [resetClicked, setResetClicked] = React.useState<boolean>(false);
 53	  const [updatedColumns, setUpdatedColumns] = React.useState<Column[]>([]);
 54	  const [filterKeys, setFilterKeys] = React.useState<string[]>([]);
 55	  const { t } = useTranslation('plugin__netobserv-plugin');
 56	  const dragDescriptionId = 'columns-drag-description';
 57	
 58	  React.useEffect(() => {
 59	    if (isModalOpen) {
 60	      setFilterKeys([]);
 61	    }
 62	  }, [isModalOpen]);
 63	
 64	  React.useEffect(() => {
 65	    if (!isModalOpen || _.isEmpty(updatedColumns)) {
 66	      setUpdatedColumns(_.cloneDeep(columns));
 67	    }
 68	    // eslint-disable-next-line react-hooks/exhaustive-deps
 69	  }, [columns, isModalOpen]);
 70	
 71	  const isFilteredColumn = React.useCallback((c: Column, fks: string[]) => {
 72	    return (
 73	      _.isEmpty(fks) ||
 74	      _.reduce(
 75	        fks,
 76	        (acc, fk) =>
 77	          (acc =
 78	            acc &&
 79	            (c.id.toLowerCase().includes(fk) ||
 80	              c.name.toLowerCase().includes(fk) ||
 81	              c.group?.toLowerCase().includes(fk) ||
 82	              false)),
 83	        true
 84	      )
 85	    );
 86	  }, []);
 87	
 88	  const onListDrop = React.useCallback(
 89	    (source: { droppableId: string; index: number }, dest?: { droppableId: string; index: number }) => {
 90	      if (!dest || source.droppableId !== dest.droppableId) {
 91	        return false;
 92	      }
 93	      const oldIndex = source.index;
 94	      const newIndex = dest.index;
 95	      if (oldIndex === newIndex) {
 96	        return false;
 97	      }
 98	      let accepted = false;
 99	      setUpdatedColumns(prev => {
100	        const filtered = prev.filter(c => isFilteredColumn(c, filterKeys));
101	        if (oldIndex < 0 || oldIndex >= filtered.length || newIndex < 0 || newIndex >= filtered.length) {
102	          return prev;
103	        }
104	        const reorderedFiltered = [...filtered];
105	        const [removed] = reorderedFiltered.splice(oldIndex, 1);
106	        reorderedFiltered.splice(newIndex, 0, removed);
107	        const next: Column[] = [];
108	        const fq = [...reorderedFiltered];
109	        for (const col of prev) {
110	          if (isFilteredColumn(col, filterKeys)) {
111	            const shifted = fq.shift();
112	            if (shifted) {
113	              next.push(shifted);
114	            }
115	          } else {
116	            next.push(col);
117	          }
118	        }
119	        accepted = true;
120	        return next;
121	      });
122	      return accepted;
123	    },
124	    [filterKeys, isFilteredColumn]
125	  );
126	
127	  const onCheck = React.useCallback(
128	    // eslint-disable-next-line @typescript-eslint/no-unused-vars
129	    (event: React.FormEvent<HTMLInputElement>, checked: boolean) => {
130	      if (event?.target && 'id' in event.target) {
131	        const columnId = (event.target as HTMLInputElement).id;
132	        setUpdatedColumns(prevColumns =>
133	          prevColumns.map(col => (col.id === columnId ? { ...col, isSelected: checked } : col))
134	        );
135	      }
136	    },
137	    []
138	  );
139	
140	  const onReset = React.useCallback(() => {
141	    setResetClicked(true);
142	    setUpdatedColumns(
143	      getDefaultColumns(config.columns, config.fields).filter(c => columns.some(existing => existing.id === c.id))
144	    );
145	  }, [columns, config.columns, config.fields]);
146	
147	  const isSaveDisabled = React.useCallback(() => {
148	    return _.isEmpty(updatedColumns.filter(c => c.isSelected));
149	  }, [updatedColumns]);
150	
151	  const getColumnFilterKeys = React.useCallback(() => {
152	    return columnFilterKeys.filter(fk => columns.some(c => isFilteredColumn(c, [fk])));
153	  }, [columns, isFilteredColumn]);
154	
155	  const filteredColumns = React.useCallback(() => {
156	    return updatedColumns.filter(c => isFilteredColumn(c, filterKeys));
157	  }, [filterKeys, isFilteredColumn, updatedColumns]);
158	
159	  const isAllSelected = React.useCallback(() => {
160	    return _.reduce(filteredColumns(), (acc, c) => (acc = acc && c.isSelected), true);
161	  }, [filteredColumns]);
162	
163	  const onSelectAll = React.useCallback(() => {
164	    const allSelected = isAllSelected();
165	    setUpdatedColumns(prevColumns =>
166	      prevColumns.map(col => (isFilteredColumn(col, filterKeys) ? { ...col, isSelected: !allSelected } : col))
167	    );
168	  }, [isAllSelected, isFilteredColumn, filterKeys]);
169	
170	  const onClose = React.useCallback(() => {
171	    setResetClicked(false);
172	    setUpdatedColumns(_.cloneDeep(columns));
173	    setModalOpen(false);
174	  }, [columns, setModalOpen]);
175	
176	  const onSave = React.useCallback(() => {
177	    if (resetClicked) {
178	      setColumnSizes({});
179	    }
180	    setColumns(updatedColumns);
181	    onClose();
182	  }, [resetClicked, setColumns, updatedColumns, onClose, setColumnSizes]);
183	
184	  const toggleChip = React.useCallback(
185	    (key: string) => {
186	      if (filterKeys.includes(key)) {
187	        setFilterKeys(filterKeys.filter(k => k !== key));
188	      } else {
189	        setFilterKeys(columnFilterKeys.filter(f => f === key || filterKeys.includes(f)));
190	      }
191	    },
192	    [filterKeys]
193	  );
194	
195	  return (
196	    <Modal
197	      id={id}
198	      title={t('Manage columns')}
199	      isOpen={isModalOpen}
200	      scrollable={true}
201	      onClose={onClose}
202	      description={
203	        <>
204	          <TextContent>
205	            <Text component={TextVariants.p}>
206	              {t('Selected columns will appear in the table.')}&nbsp;
207	              {t('Click and drag the items to reorder the columns in the table.')}
208	            </Text>
209	          </TextContent>
210	          <Flex className="popup-header-margin">
211	            <FlexItem flex={{ default: 'flex_4' }}>
212	              <Flex className="flex-gap">
213	                {getColumnFilterKeys().map(key => {
214	                  return (
215	                    <FlexItem
216	                      key={key}
217	                      onClick={() => toggleChip(key)}
218	                      className={`custom-chip ${
219	                        filterKeys.includes(key) ? 'selected' : 'unselected'
220	                      } buttonless gap pointer`}
221	                    >
222	                      <Text component={TextVariants.p}>{key}</Text>
223	                    </FlexItem>
224	                  );
225	                })}
226	              </Flex>
227	            </FlexItem>
228	            <FlexItem flex={{ default: 'flex_1' }} className="flex-center">
229	              {_.isEmpty(filteredColumns()) ? (
230	                <Button isInline onClick={() => setFilterKeys([])} variant="link">
231	                  {t('Clear filters')}
232	                </Button>
233	              ) : (
234	                <Button isInline onClick={onSelectAll} variant="link">
235	                  {`${isAllSelected() ? t('Unselect all') : t('Select all')}${
236	                    !_.isEmpty(filterKeys) ? ' ' + filterKeys.join(',') : ''
237	                  }`}
238	                </Button>
239	              )}
240	            </FlexItem>
241	          </Flex>
242	        </>
243	      }
244	      footer={
245	        <>
246	          <Button data-test="columns-reset-button" key="reset" variant="link" onClick={() => onReset()}>
247	            {t('Restore default columns')}
248	          </Button>
249	          <Button data-test="columns-cancel-button" key="cancel" variant="link" onClick={() => onClose()}>
250	            {t('Cancel')}
251	          </Button>
252	          <Tooltip content={t('At least one column must be selected')} trigger="" isVisible={isSaveDisabled()}>
253	            <Button
254	              data-test="columns-save-button"
255	              isDisabled={isSaveDisabled()}
256	              key="confirm"
257	              variant="primary"
258	              onClick={() => onSave()}
259	            >
260	              {t('Save')}
261	            </Button>
262	          </Tooltip>
263	        </>
264	      }
265	    >
266	      <div className="co-m-form-row" id="drag-drop-container">
267	        <DragDrop onDrop={onListDrop}>
268	          <Droppable hasNoWrapper zone={COLUMNS_DRAG_ZONE} droppableId="columns-list">
269	            <DataList
270	              aria-label="Table column management"
271	              data-test="table-column-management"
272	              id="table-column-management"
273	              className="centered-list"
274	              isCompact
275	            >
276	              {filteredColumns().map(column => {
277	                const rowLabelId = `table-column-management-item-${column.id}`;
278	                return (
279	                  <Draggable key={column.id} hasNoWrapper>
280	                    <DataListItem aria-labelledby={rowLabelId} id={`table-column-management-row-${column.id}`}>
281	                      <DataListItemRow>
282	                        <DataListControl className="netobserv-data-list-control">
283	                          <DataListDragButton
284	                            aria-label={t('Reorder column')}
285	                            aria-labelledby={rowLabelId}
286	                            aria-describedby={dragDescriptionId}
287	                            aria-pressed={false}
288	                          />
289	                          <DataListCheck
290	                            aria-labelledby={rowLabelId}
291	                            isChecked={column.isSelected}
292	                            id={column.id}
293	                            onChange={onCheck}
294	                            otherControls
295	                          />
296	                        </DataListControl>
297	                        <DataListItemCells
298	                          dataListCells={[
299	                            <DataListCell key={`data-list-cell-${column.id}`} className="center">
300	                              <label htmlFor={column.id} id={rowLabelId}>
301	                                {getFullColumnName(column)}
302	                              </label>
303	                            </DataListCell>
304	                          ]}
305	                        />
306	                      </DataListItemRow>
307	                    </DataListItem>
308	                  </Draggable>
309	                );
310	              })}
311	            </DataList>
312	          </Droppable>
313	          <div className="pf-v6-screen-reader" id={dragDescriptionId}>
314	            {t(
315	              // eslint-disable-next-line max-len
316	              'Press space or enter to begin dragging, and use the arrow keys to navigate up or down. Press enter to confirm the drag, or any other key to cancel the drag operation.'
317	            )}
318	          </div>
319	        </DragDrop>
320	      </div>
321	    </Modal>
322	  );
323	};
324	
325	export default ColumnsModal;

