  1	import {
  2	  Button,
  3	  DataList,
  4	  DataListCell,
  5	  DataListCheck,
  6	  DataListControl,
  7	  DataListDragButton,
  8	  DataListItem,
  9	  DataListItemCells,
 10	  DataListItemRow,
 11	  DragDrop,
 12	  Draggable,
 13	  Droppable,
 14	  Flex,
 15	  FlexItem,
 16	  Content,
 17	  ContentVariants,
 18	  Tooltip
 19	} from '@patternfly/react-core';
 20	import * as _ from 'lodash';
 21	import * as React from 'react';
 22	import { useTranslation } from 'react-i18next';
 23	import { Config } from '../../model/config';
 24	import { Column, ColumnSizeMap, getDefaultColumns, getFullColumnName } from '../../utils/columns';
 25	import './columns-modal.css';
 26	import Modal from './modal';
 27	
 28	const COLUMNS_DRAG_ZONE = 'netobs-columns-modal';
 29	
 30	export const columnFilterKeys = ['source', 'destination', 'time', 'host', 'namespace', 'owner', 'ip', 'dns'];
 31	
 32	export interface ColumnsModalProps {
 33	  isModalOpen: boolean;
 34	  setModalOpen: (v: boolean) => void;
 35	  columns: Column[];
 36	  setColumns: (v: Column[]) => void;
 37	  setColumnSizes: (v: ColumnSizeMap) => void;
 38	  config: Config;
 39	  id?: string;
 40	}
 41	
 42	export const ColumnsModal: React.FC<ColumnsModalProps> = ({
 43	  id,
 44	  config,
 45	  isModalOpen,
 46	  setModalOpen,
 47	  columns,
 48	  setColumns,
 49	  setColumnSizes
 50	}) => {
 51	  const [resetClicked, setResetClicked] = React.useState<boolean>(false);
 52	  const [updatedColumns, setUpdatedColumns] = React.useState<Column[]>([]);
 53	  const [filterKeys, setFilterKeys] = React.useState<string[]>([]);
 54	  const { t } = useTranslation('plugin__netobserv-plugin');
 55	  const dragDescriptionId = 'columns-drag-description';
 56	
 57	  React.useEffect(() => {
 58	    if (isModalOpen) {
 59	      setFilterKeys([]);
 60	    }
 61	  }, [isModalOpen]);
 62	
 63	  React.useEffect(() => {
 64	    if (!isModalOpen || _.isEmpty(updatedColumns)) {
 65	      setUpdatedColumns(_.cloneDeep(columns));
 66	    }
 67	    // eslint-disable-next-line react-hooks/exhaustive-deps
 68	  }, [columns, isModalOpen]);
 69	
 70	  const isFilteredColumn = React.useCallback((c: Column, fks: string[]) => {
 71	    return (
 72	      _.isEmpty(fks) ||
 73	      _.reduce(
 74	        fks,
 75	        (acc, fk) =>
 76	          (acc =
 77	            acc &&
 78	            (c.id.toLowerCase().includes(fk) ||
 79	              c.name.toLowerCase().includes(fk) ||
 80	              c.group?.toLowerCase().includes(fk) ||
 81	              false)),
 82	        true
 83	      )
 84	    );
 85	  }, []);
 86	
 87	  const onListDrop = React.useCallback(
 88	    (source: { droppableId: string; index: number }, dest?: { droppableId: string; index: number }) => {
 89	      if (!dest || source.droppableId !== dest.droppableId) {
 90	        return false;
 91	      }
 92	      const oldIndex = source.index;
 93	      const newIndex = dest.index;
 94	      if (oldIndex === newIndex) {
 95	        return false;
 96	      }
 97	      let accepted = false;
 98	      setUpdatedColumns(prev => {
 99	        const filtered = prev.filter(c => isFilteredColumn(c, filterKeys));
100	        if (oldIndex < 0 || oldIndex >= filtered.length || newIndex < 0 || newIndex >= filtered.length) {
101	          return prev;
102	        }
103	        const reorderedFiltered = [...filtered];
104	        const [removed] = reorderedFiltered.splice(oldIndex, 1);
105	        reorderedFiltered.splice(newIndex, 0, removed);
106	        const next: Column[] = [];
107	        const fq = [...reorderedFiltered];
108	        for (const col of prev) {
109	          if (isFilteredColumn(col, filterKeys)) {
110	            const shifted = fq.shift();
111	            if (shifted) {
112	              next.push(shifted);
113	            }
114	          } else {
115	            next.push(col);
116	          }
117	        }
118	        accepted = true;
119	        return next;
120	      });
121	      return accepted;
122	    },
123	    [filterKeys, isFilteredColumn]
124	  );
125	
126	  const onCheck = React.useCallback(
127	    // eslint-disable-next-line @typescript-eslint/no-unused-vars
128	    (event: React.FormEvent<HTMLInputElement>, checked: boolean) => {
129	      if (event?.target && 'id' in event.target) {
130	        const columnId = (event.target as HTMLInputElement).id;
131	        setUpdatedColumns(prevColumns =>
132	          prevColumns.map(col => (col.id === columnId ? { ...col, isSelected: checked } : col))
133	        );
134	      }
135	    },
136	    []
137	  );
138	
139	  const onReset = React.useCallback(() => {
140	    setResetClicked(true);
141	    setUpdatedColumns(
142	      getDefaultColumns(config.columns, config.fields).filter(c => columns.some(existing => existing.id === c.id))
143	    );
144	  }, [columns, config.columns, config.fields]);
145	
146	  const isSaveDisabled = React.useCallback(() => {
147	    return _.isEmpty(updatedColumns.filter(c => c.isSelected));
148	  }, [updatedColumns]);
149	
150	  const getColumnFilterKeys = React.useCallback(() => {
151	    return columnFilterKeys.filter(fk => columns.some(c => isFilteredColumn(c, [fk])));
152	  }, [columns, isFilteredColumn]);
153	
154	  const filteredColumns = React.useCallback(() => {
155	    return updatedColumns.filter(c => isFilteredColumn(c, filterKeys));
156	  }, [filterKeys, isFilteredColumn, updatedColumns]);
157	
158	  const isAllSelected = React.useCallback(() => {
159	    return _.reduce(filteredColumns(), (acc, c) => (acc = acc && c.isSelected), true);
160	  }, [filteredColumns]);
161	
162	  const onSelectAll = React.useCallback(() => {
163	    const allSelected = isAllSelected();
164	    setUpdatedColumns(prevColumns =>
165	      prevColumns.map(col => (isFilteredColumn(col, filterKeys) ? { ...col, isSelected: !allSelected } : col))
166	    );
167	  }, [isAllSelected, isFilteredColumn, filterKeys]);
168	
169	  const onClose = React.useCallback(() => {
170	    setResetClicked(false);
171	    setUpdatedColumns(_.cloneDeep(columns));
172	    setModalOpen(false);
173	  }, [columns, setModalOpen]);
174	
175	  const onSave = React.useCallback(() => {
176	    if (resetClicked) {
177	      setColumnSizes({});
178	    }
179	    setColumns(updatedColumns);
180	    onClose();
181	  }, [resetClicked, setColumns, updatedColumns, onClose, setColumnSizes]);
182	
183	  const toggleChip = React.useCallback(
184	    (key: string) => {
185	      if (filterKeys.includes(key)) {
186	        setFilterKeys(filterKeys.filter(k => k !== key));
187	      } else {
188	        setFilterKeys(columnFilterKeys.filter(f => f === key || filterKeys.includes(f)));
189	      }
190	    },
191	    [filterKeys]
192	  );
193	
194	  return (
195	    <Modal
196	      id={id}
197	      title={t('Manage columns')}
198	      isOpen={isModalOpen}
