 1	import { act, fireEvent, render, screen, waitFor } from '@testing-library/react';
 2	import * as React from 'react';
 3	
 4	import { Config, defaultConfig } from '../../../model/config';
 5	import { ColumnConfigSampleDefs, ShuffledColumnSample } from '../../__tests-data__/columns';
 6	import ColumnsModal from '../columns-modal';
 7	
 8	describe('<ColumnsModal />', () => {
 9	  const props = {
10	    isModalOpen: true,
11	    setModalOpen: jest.fn(),
12	    config: { ...defaultConfig, columns: ColumnConfigSampleDefs } as Config,
13	    columns: ShuffledColumnSample,
14	    setColumns: jest.fn(),
15	    setColumnSizes: jest.fn(),
16	    id: 'columns-modal'
17	  };
18	
19	  beforeEach(() => {
20	    jest.useFakeTimers();
21	    jest.clearAllMocks();
22	  });
23	
24	  afterEach(() => {
25	    jest.runOnlyPendingTimers();
26	    jest.useRealTimers();
27	  });
28	
29	  it('should render component', async () => {
30	    render(<ColumnsModal {...props} />);
31	    await act(async () => {
32	      jest.runAllTimers();
33	    });
34	  });
35	
36	  it('should save once', async () => {
37	    render(<ColumnsModal {...props} />);
38	    await act(async () => {
39	      jest.runAllTimers();
40	    });
41	
42	    const confirmButton = document.querySelector('.pf-v6-c-button.pf-m-primary') as HTMLElement;
43	    expect(confirmButton).toBeTruthy();
44	
45	    await act(async () => {
46	      fireEvent.click(confirmButton);
47	      jest.runAllTimers();
48	    });
49	    expect(props.setColumns).toHaveBeenCalledTimes(1);
50	  });
51	
52	  it('should update columns selected on save', async () => {
53	    render(<ColumnsModal {...props} />);
54	    await act(async () => {
55	      jest.runAllTimers();
56	    });
57	
58	    await waitFor(() => {
59	      expect(screen.getAllByRole('switch').length).toBeGreaterThanOrEqual(2);
60	    });
61	
62	    const checkboxes = screen.getAllByRole('switch');
63	    await act(async () => {
64	      fireEvent.click(checkboxes[0]);
65	      fireEvent.click(checkboxes[1]);
66	      jest.runAllTimers();
67	    });
68	
69	    const saveButton = document.querySelector('.pf-v6-c-button.pf-m-primary') as HTMLElement;
70	    await act(async () => {
71	      fireEvent.click(saveButton);
